 1	import React, { useEffect, useState } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { MigrationPolicyModelGroupVersionKind } from '@kubevirt-ui/kubevirt-api/console';
 5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
 6	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 7	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 8	import { dateTimeFormatter } from '@kubevirt-utils/components/Timestamp/utils/datetime';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import { getResourceUrl } from '@kubevirt-utils/resources/shared';
11	import useVirtualMachineInstanceMigration from '@kubevirt-utils/resources/vmi/hooks/useVirtualMachineInstanceMigration';
12	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
13	import { Popover, PopoverPosition, Stack, StackItem } from '@patternfly/react-core';
14	
15	import { getMigrationPhaseIcon } from './utils';
16	
17	type MigrationProgressPopoverProps = React.PropsWithChildren<{
18	  vmi: V1VirtualMachineInstance;
19	}>;
20	
21	const MigrationProgressPopover: React.FC<MigrationProgressPopoverProps> = ({ children, vmi }) => {
22	  const { t } = useKubevirtTranslation();
23	  const vmim = useVirtualMachineInstanceMigration(vmi);
24	  const Icon = getMigrationPhaseIcon(vmim?.status?.phase);
25	  const [seconds, setSeconds] = useState(0);
26	  const [minutes, setMinutes] = useState(0);
27	
28	  useEffect(() => {
29	    if (vmi?.status?.migrationState?.startTimestamp) {
30	      const interval = setInterval(() => {
31	        setSeconds((sec) => {
32	          if (sec + 1 === 60) {
33	            setMinutes((min) => min + 1);
34	            return 0;
35	          }
36	          return sec + 1;
37	        });
38	      }, 1000);
39	      return () => clearInterval(interval);
40	    }
41	    if (vmi?.status?.migrationState?.endTimestamp) {
42	      setSeconds(0);
43	      setMinutes(0);
44	    }
45	  }, [vmi?.status?.migrationState?.endTimestamp, vmi?.status?.migrationState?.startTimestamp]);
46	
47	  return (
48	    <Popover
49	      bodyContent={
50	        <Stack hasGutter>
51	          <StackItem>
52	            <b>{t('Phase')}</b> <Icon /> {vmim?.status?.phase}
53	          </StackItem>
54	          <StackItem>
55	            <b>{t('Started')}</b>{' '}
56	            {vmi?.status?.migrationState?.startTimestamp &&
57	              dateTimeFormatter.format(new Date(vmi?.status?.migrationState?.startTimestamp))}
58	          </StackItem>
59	          <StackItem>
60	            <b>{t('Elapsed time')}</b>{' '}
61	            {t('{{minutes}}{{seconds}} seconds', {
62	              minutes: minutes ? `${minutes} minutes, ` : null,
63	              seconds,
64	            })}
65	          </StackItem>
66	          <StackItem>
67	            <b>{t('Policy')}</b>{' '}
68	            {vmi?.status?.migrationState?.migrationPolicyName ? (
69	              <ResourceLink
70	                groupVersionKind={MigrationPolicyModelGroupVersionKind}
71	                name={vmi.status.migrationState.migrationPolicyName}
72	              />
73	            ) : (
74	              <MutedTextSpan text="No MigrationPolicy" />
75	            )}
76	          </StackItem>
77	          <StackItem>
78	            <Link
79	              to={`${getResourceUrl({
80	                model: VirtualMachineModel,
81	                resource: vmi,
82	              })}/metrics?migration`}
83	            >
84	              {t('Migration metrics')}
85	            </Link>
86	          </StackItem>
87	        </Stack>
88	      }
89	      headerContent={'VirtualMachine migration'}
90	      position={PopoverPosition.right}
91	    >
92	      <>{children}</>
93	    </Popover>
94	  );
95	};
96	
97	export default MigrationProgressPopover;

